107	test('sessions page lists sharded sessions, lazy-loads bundle bodies, and refreshes live', async ({
108		page
109	}) => {
110		let includeLiveSession = false;
111		let detailRequested = false;
112	
113		await page.route('/graphql', async (route) => {
114			const body = route.request().postDataJSON() as { query: string };
115			if (body.query.includes('NodeInfo')) {
116				await route.fulfill({
117					status: 200,
118					contentType: 'application/json',
119					body: JSON.stringify({ data: { nodeInfo: NODE_INFO } })
120				});
121			} else if (body.query.includes('Projects')) {
122				await route.fulfill({
123					status: 200,
124					contentType: 'application/json',
125					body: JSON.stringify({ data: { projects: { edges: PROJECTS.map((node) => ({ node })) } } })
126				});
127			} else if (body.query.includes('AgentSessions') || body.query.includes('agentSessions')) {
128				const rows = includeLiveSession
129					? [liveSession, latestBundleSession, olderSession]
130					: [latestBundleSession, olderSession];
131				await route.fulfill({
132					status: 200,
133					contentType: 'application/json',
134					body: JSON.stringify({ data: sessionsPayload(rows) })
135				});
136			} else if (body.query.includes('AgentSessionDetail') || body.query.includes('agentSession')) {
137				detailRequested = true;
138				await route.fulfill({
139					status: 200,
140					contentType: 'application/json',
141					body: JSON.stringify({
142						data: {
143							agentSession: {
144								id: latestBundleSession.id,
145								prompt: 'bundle prompt body',
146								response: 'bundle response body',
147								stderr: ''
148							}
149						}
150					})
151				});
152			} else {
153				await route.continue();
154			}
155		});
156	
157		await page.goto(BASE_URL);
158	
159		await expect(page.getByRole('heading', { name: 'Sessions' })).toBeVisible();
160		await expect(page.getByText(/Sessions are immutable agent-run history/)).toBeVisible();
161		await expect(page.getByRole('link', { name: 'Workers →' })).toHaveAttribute('href', /\/workers$/);
162		await expect(page.getByText('codex', { exact: true })).toBeVisible();
163		await expect(page.getByText('gpt-5.4')).toBeVisible();
164		await expect(page.getByText('Cash paid')).toBeVisible();
165		await expect(page.getByText('Subscription value')).toBeVisible();
166		await expect(page.getByText('Local sessions')).toBeVisible();
167		await expect(page.getByText('$0.02', { exact: true })).toBeVisible();
168		await expect(page.getByText('$0.01', { exact: true })).toBeVisible();
169		await expect(page.getByLabel(/cash: Billed by pay-per-token APIs/)).toBeVisible();
170		await expect(page.getByLabel(/sub: Dollar-equivalent for tokens consumed/)).toBeVisible();
171		await expect(page.getByText(/No sessions recorded between/)).toBeVisible();
172		await expect(page.getByRole('row', { name: /codex.*gpt-5\.4.*4\/22\/2026/i })).toBeVisible();
173	
174		await page.getByText('Cash paid').hover();
175		await expect(page.getByRole('tooltip', { name: /Billed by pay-per-token APIs/ })).toBeVisible();
176		await page.getByText('Subscription value').hover();
177		await expect(
178			page.getByRole('tooltip', { name: /Dollar-equivalent for tokens consumed/ })
179		).toBeVisible();
180		await page.getByText('Local sessions').hover();
181		await expect(page.getByRole('tooltip', { name: /Sessions served locally/ })).toBeVisible();
182	
183		await page.getByLabel(/cash: Billed by pay-per-token APIs/).hover();
184		await expect(page.getByRole('tooltip', { name: /OpenRouter, direct API keys/ })).toBeVisible();
185	
186		await page.getByRole('row', { name: /codex.*gpt-5\.4/i }).click();
187		await expect.poll(() => detailRequested).toBe(true);
188		await expect(page.getByRole('link', { name: 'worker-session-owner' })).toHaveAttribute(
189			'href',
190			/\/workers\/worker-session-owner$/
