131				if (isExternal) {
132					return `<a href="${href}" target="_blank" rel="noopener noreferrer"`;
133				}
134				const resolvedPath = resolvePath(href, baseDir);
135				return `<a href="#" data-ddx-intra-path="${resolvedPath}"`;
136			});
137		}
