5	const SESSIONS_QUERY = gql`
6		query SessionsPage($first: Int, $projectId: ID!) {
7			agentSessions(first: $first) {
8				edges {
9					node {
10						id
11						projectId
12						beadId
13						workerId
14						harness
15						model
16						effort
17						status
18						startedAt
19						endedAt
20						durationMs
21						cost
22						billingMode
23						tokens {
24							prompt
25							completion
26							total
27							cached
28						}
29						outcome
30						detail
31					}
32					cursor
33				}
34				pageInfo {
35					hasNextPage
36					endCursor
37				}
38				totalCount
39			}
40			sessionsCostSummary(projectId: $projectId) {
41				cashUsd
42				subscriptionEquivUsd
43				localSessionCount
44				localEstimatedUsd
45			}
46		}
47	`;
48	
49	export const SESSION_DETAIL_QUERY = gql`
50		query AgentSessionDetail($id: ID!) {
51			agentSession(id: $id) {
52				id
53				prompt
54				response
55				stderr
56			}
57		}
58	`;
59	
60	export const SESSION_EXECUTION_QUERY = gql`
61		query SessionExecution($projectID: ID!, $sessionID: String!) {
62			executionBySessionId(projectId: $projectID, sessionId: $sessionID) {
63				id
64			}
65		}
66	`;
67	
68	interface TokenUsage {
69		prompt: number | null;
70		completion: number | null;
71		total: number | null;
72		cached: number | null;
73	}
74	
75	export interface SessionNode {
76		id: string;
77		projectId: string;
78		beadId: string | null;
79		workerId: string | null;
80		harness: string;
81		model: string;
82		effort: string;
83		status: string;
84		startedAt: string;
85		endedAt: string | null;
86		durationMs: number;
87		cost: number | null;
88		billingMode: 'paid' | 'subscription' | 'local';
89		tokens: TokenUsage | null;
90		outcome: string | null;
91		detail: string | null;
92		prompt?: string | null;
93		response?: string | null;
94		stderr?: string | null;
95	}
96	
97	interface SessionEdge {
98		node: SessionNode;
99		cursor: string;
100	}
101	
102	interface SessionConnection {
103		edges: SessionEdge[];
104		pageInfo: { hasNextPage: boolean; endCursor: string | null };
105		totalCount: number;
106	}
107	
108	interface SessionsResult {
109		agentSessions: SessionConnection;
110		sessionsCostSummary: SessionsCostSummary;
111	}
112	
113	export interface SessionsCostSummary {
114		cashUsd: number;
115		subscriptionEquivUsd: number;
116		localSessionCount: number;
117		localEstimatedUsd: number | null;
118	}
119	
120	export const load: PageLoad = async ({ params, fetch }) => {
121		const client = createClient(fetch as unknown as typeof globalThis.fetch);
122		const data = await client.request<SessionsResult>(SESSIONS_QUERY, {
123			first: 100,
124			projectId: params.projectId
125		});
126		const filteredEdges = data.agentSessions.edges.filter(
127			(e) => e.node.projectId === params.projectId
128		);
129		return {
130			nodeId: params.nodeId,
131			projectId: params.projectId,
132			sessions: {
133				...data.agentSessions,
134				edges: filteredEdges,
135				totalCount: filteredEdges.length
136			},
137			costSummary: data.sessionsCostSummary
138		};
139	};
